import pandas as pd

# We have env['data_2'] which contains all articles published in 2015.
df_2015 = pd.DataFrame(env['data_2'])

# We need to query MongoDB in chunks to avoid the 2MB limit or query string limit
article_ids_2015 = df_2015['article_id'].tolist()

# Let's just write a python script to query MongoDB in chunks of 1000
import json

chunk_size = 1000
chunks = [article_ids_2015[i:i + chunk_size] for i in range(0, len(article_ids_2015), chunk_size)]

queries = []
for i, chunk in enumerate(chunks):
    query = [
      {
        "$match": {
          "article_id": {"$in": chunk},
          "$or": [
            {"title": {"$regex": "Iraq|UN|minister|official|government|war|military|peace|crisis|election|nuclear|sudan", "$options": "i"}},
            {"description": {"$regex": "Iraq|UN|minister|official|government|war|military|peace|crisis|election|nuclear|sudan", "$options": "i"}}
          ]
        }
      },
      {
        "$project": {
          "article_id": 1
        }
      }
    ]
    queries.append(query)

print(f"Created {len(queries)} queries")
# We will execute the first one to see if it works
print(json.dumps(queries[0]))

