import json
import pandas as pd

# We have env['data_2'] which contains all articles published in 2015.
df_2015 = pd.DataFrame(env['data_2'])
article_ids_2015 = df_2015['article_id'].tolist()

# Let's just query MongoDB for ALL World articles, and then we'll intersect in Python.
# This avoids the 2MB limit because we only project article_id.
query = [
  {
    "$match": {
      "$or": [
        {"title": {"$regex": "Iraq|UN|minister|official|government|war|military|peace|crisis|election|nuclear|sudan", "$options": "i"}},
        {"description": {"$regex": "Iraq|UN|minister|official|government|war|military|peace|crisis|election|nuclear|sudan", "$options": "i"}}
      ]
    }
  },
  {
    "$project": {
      "article_id": 1
    }
  }
]

# We can't do that directly because it was too large.
# Let's query MongoDB in chunks of 1000 IDs from 2015.
chunk_size = 1000
chunks = [article_ids_2015[i:i + chunk_size] for i in range(0, len(article_ids_2015), chunk_size)]

# We will generate the queries and the user can run them, or we can just use execute_python to run them if we had a mongo client.
# Since we don't have a mongo client in execute_python, we have to use query_db.

